"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["8441"],{59822(e,i,t){t.r(i),t.d(i,{default:()=>r});var a=t(74848),o=t(47643),n=JSON.parse('{"id":95,"it":{"title":"Architetto IT","prompt":"I want you to act as an IT Architect. I will provide some details about the functionality of an application or other digital product, and it will be your job to come up with ways to integrate it into the IT landscape. This could involve analyzing business requirements, performing a gap analysis and mapping the functionality of the new system to the existing IT landscape. Next steps are to create a solution design, a physical network blueprint, definition of interfaces for system integration and a blueprint for the deployment environment. Respond in Italian. My first request is [dettagli delle funzionalit\xe0 dell\'applicazione]","description":"Vorrei che assumeste il ruolo di un architetto IT. Vi fornir\xf2 alcuni dettagli sulle funzionalit\xe0 di un\'applicazione o di un altro prodotto digitale e il vostro compito sar\xe0 quello di capire come integrarlo nell\'ambiente IT. Ci\xf2 pu\xf2 comportare l\'analisi dei requisiti aziendali, l\'esecuzione di una gap analysis e la mappatura delle funzionalit\xe0 del nuovo sistema nell\'ambiente IT esistente. I passi successivi consistono nel creare un progetto di soluzione, un blueprint della rete fisica che definisca le interfacce per l\'integrazione del sistema e un blueprint dell\'ambiente di distribuzione.","remark":"Progettare soluzioni di sistema dal punto di vista di un architetto IT."},"tags":["code"],"website":"https://github.com/f/awesome-chatgpt-prompts#act-as-an-it-architect","count":3289,"related":[{"id":90,"title":"Problemi di programmazione IT","remark":"Comunit\xe0 di programmazione per la simulazione che risponde alle vostre domande e fornisce codice risolutivo."},{"id":218,"title":"Aiuto alla programmazione CAN","remark":"Lasciate che sia l\'intelligenza artificiale a porre domande e a guidare l\'uomo, passo dopo passo, attraverso il codice. Raccolto da Snackprompt, condiviso da @fuxinsen."},{"id":173,"title":"interprete di codice","remark":"Lasciare che l\'intelligenza artificiale spieghi cosa fa ogni passo del codice. Contributo di @Tractor1928, successivamente modificato da @yiqiongwu."}],"metaTitle":"Architetto IT: Integrazione","metaDescription":"Integri app? Analizza bisogni e funzioni. Crea design di soluzioni e schemi di rete per un deployment fluido. Provalo ora.","faq":[{"q":"Quanto sono affidabili le architetture enterprise?","a":"Le macro-direzioni (microservizi, event-driven, DDD) sono descritte bene; le scelte tecnologiche concrete vanno valutate contro debito tecnico e competenze del team. L\'AI non sa se il tuo team padroneggia Kubernetes: una soluzione che consiglia potrebbe richiedere 6 mesi solo per l\'onboarding."},{"q":"L\'AI considera i requisiti non funzionali (compliance, sicurezza)?","a":"Di default non li approfondisce. Per finanza/sanit\xe0/dati personali scrivi esplicitamente \xabsoluzione conforme a GDPR/ISO 27001/HIPAA\xbb: l\'AI aggiunge i moduli relativi (log di audit, cifratura dati, isolamento degli accessi). Senza richiesta esplicita i dettagli di compliance vengono quasi tutti tralasciati."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T02:40:13+00:00"}');function r(){return(0,a.jsx)(o.A,{prompt:n,currentLanguage:"it"})}}}]);